const tableName = "Mystery Descriptors - Clues";

const table = game.tables.getName(tableName);

if (!table) {
  ui.notifications.error(`RollTable "${tableName}" not found.`);
  return;
}

const results = await table.drawMany(2, { displayChat: false });

let content = `<h2>🔎 Mystery Clues</h2><ol>`;

for (let r of results.results) {
  const rollNumber = r.range[0];
  content += `<li><strong>[${rollNumber}]</strong> ${r.text}</li>`;
}

content += `</ol>`;

ChatMessage.create({
  user: game.user.id,
  speaker: ChatMessage.getSpeaker(),
  content: content
});
